def base(e):
    return head(tail(e))
def exponent(e):
    return head(tail(tail(e)))
def make_exp(base, exp):
    return (1
            if number_equal(exp, 0)
            else base
            if number_equal(exp, 1)
            else llist("**", base, exp))
def is_exp(x):
    return is_pair(x) and head(x) == "**"
def deriv(exp, variable):
    return (0
            if is_number(exp)
            else (1 if is_same_variable(exp, variable) else 0)
            if is_variable(exp)
            else make_sum(deriv(addend(exp), variable),
                          deriv(augend(exp), variable))
            if is_sum(exp)
            else make_sum(make_product(multiplier(exp),
                                       deriv(multiplicand(exp), 
                                             variable)),
		          make_product(deriv(multiplier(exp),
                                             variable),
                                       multiplicand(exp)))
            if is_product(exp)
            else make_product(make_product(exponent(exp),
                                           make_exp(base(exp),
                                                    exponent(exp) - 1)),
                              deriv(base(exp), variable))
            if is_exp(exp)
            else error("unknown expression type -- deriv", exp))






