def make_sum(a1, a2):
    return (a2
            if number_equal(a1, 0)
            else a1
            if number_equal(a2, 0)
            else a1 + a2
            if is_number(a1) and is_number(a2)
            else llist(a1, "+", a2))
def is_sum(x):
    return is_pair(x) and head(tail(x)) == "+"
def addend(s):
    return head(s)
def augend(s):
    return head(tail(tail(s)))
def make_product(m1, m2):
    return (0
            if number_equal(m1, 0) or number_equal(m2, 0)
            else m2
            if number_equal(m1, 1)
            else m1
            if number_equal(m2, 1)
            else m1 * m2
            if is_number(m1) and is_number(m2)
            else llist(m1, "*", m2))
def is_product(x):
    return is_pair(x) and head(tail(x)) == "*"
def multiplier(s):
    return head(s)
def multiplicand(s):
    return head(tail(tail(s)))
def deriv(exp, variable):
